SELECT recording_time
FROM recordings
WHERE data_quality = 'good';

SELECT COUNT(*) AS total_recordings
FROM recordings
WHERE subject_id = 1;

SELECT AVG(value) AS average_value
FROM signal_data
WHERE artifact = 0;

SELECT subject_id, AVG(duration) AS average_duration
FROM recordings
GROUP BY subject_id;

SELECT AVG(feature_value) AS average_heart_rate
FROM signal_features
WHERE feature_name = 'heart_rate';
